import Iterator from "../../../../../../../../../../../subject_repositories/delta/src/OpIterator.ts";

describe("Iterator.rest()", () => {
  it("should return remaining ops from current index when offset is 0", () => {
    const ops = [
      { insert: "hello" },
      { insert: "world" },
      { insert: "!" },
    ];
    const iter = new Iterator(ops);

    // Advance to consume first op fully, so offset === 0 and index === 1
    iter.next(); // consumes "hello" fully

    // Now offset should be 0, index should be 1
    // rest() should return ops from index 1 onwards
    const result = iter.rest();

    expect(result).toEqual([{ insert: "world" }, { insert: "!" }]);
  });
});
```

Looking at the mutation more carefully:

Original code:
```
if (false) {
  // placeholder
} else if (this.offset === 0) {
  return this.ops.slice(this.index);
} else {
  // handle non-zero offset case
}
```

Mutated code:
```
if (false) {
  // placeholder
} else if (false) {  // <-- mutation: offset === 0 becomes false
  return this.ops.slice(this.index);
} else {
  // handle non-zero offset case - always executed now
}
```

When `offset === 0`, the original returns `this.ops.slice(this.index)` directly. The mutated code falls through to the `else` branch which calls `this.next()` and then slices. The key difference: the `else` branch modifies `this.index` and `this.offset` temporarily and restores them, but it also calls `this.next()` which returns a different op than just slicing.

When offset is 0, the `else` branch would call `next()` (consuming the full current op), then slice from the new index. This should produce the same result... but wait, it also resets `this.offset = offset` and `this.index = index` after. So the returned array should be the same.

The real difference: when `offset === 0`, the `else` branch calls `next()` which returns `ops[index]` as a full op, then concatenates with `ops.slice(index+1)`. This is equivalent to `ops.slice(index)`. So results are the same...

The difference must be in side effects. The `else` branch temporarily modifies state. But it restores it. Unless the iterator state after `rest()` differs.

```typescript
import Iterator from "../../../../../../../../../../../subject_repositories/delta/src/OpIterator.ts";

describe("Iterator.rest()", () => {
  it("should not modify iterator state when offset is 0", () => {
    const ops = [
      { insert: "hello" },
      { insert: "world" },
    ];
    const iter = new Iterator(ops);

    // offset === 0, index === 0
    iter.rest();

    // After rest(), state should be unchanged - next() should still return first op
    const nextOp = iter.next();
    expect(nextOp).toEqual({ insert: "hello" });
  });
});
```
